import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Fabric 和模组简介","description":"Minecraft：Java 版中 Fabric 和模组的简要介绍。","frontmatter":{"title":"Fabric 和模组简介","description":"Minecraft：Java 版中 Fabric 和模组的简要介绍。","authors":["IMB11","itsmiir"],"authors-nogithub":["basil4088"],"files":[]},"headers":[],"relativePath":"zh_cn/1.21.4/develop/getting-started/introduction-to-fabric-and-modding.md","filePath":"versions/1.21.4/translated/zh_cn/develop/getting-started/introduction-to-fabric-and-modding.md","lastUpdated":1760721669000}`);var a={name:`zh_cn/1.21.4/develop/getting-started/introduction-to-fabric-and-modding.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Fabric 和模组简介 <a class="header-anchor" href="#h1" aria-label="Permalink to “Fabric 和模组简介”">​</a></h1><h2 id="prerequisites" tabindex="-1">先决条件 <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “先决条件”">​</a></h2><p>在开始学习之前，你应该对 Java 开发有基本的了解，并对面向对象编程（OOP）有所认识。</p><p>如果你不熟悉这些概念，在开始开发之前，你可能需要了解一些有关 Java 和 OOP 的教程，以下是可以用来学习 Java 和 OOP 的一些资源：</p><ul><li><a href="https://www.w3schools.com/java/" target="_blank" rel="noreferrer">W3: Java Tutorials</a></li><li><a href="https://www.codecademy.com/learn/learn-java" target="_blank" rel="noreferrer">Codecademy: Learn Java</a></li><li><a href="https://www.w3schools.com/java/java_oop.asp" target="_blank" rel="noreferrer">W3: Java OOP</a></li><li><a href="https://medium.com/@Adekola_Olawale/beginners-guide-to-object-oriented-programming-a94601ea2fbd" target="_blank" rel="noreferrer">Medium: Introduction to OOP</a></li></ul><h3 id="terminology" tabindex="-1">术语 <a class="header-anchor" href="#terminology" aria-label="Permalink to “术语”">​</a></h3><p>开始之前，先来看看使用 Fabric 编写模组时会遇到的一些术语：</p><ul><li><strong>模组（Mod）</strong>： 对游戏的修改，添加新功能或更改现有功能。</li><li><strong>模组加载器（Mod Loader）</strong>： 将模组载入游戏的工具，例如 Fabric Loader。</li><li><strong>Mixin</strong>： 运行时修改游戏代码的工具——更多信息请参阅 <a href="https://fabricmc.net/wiki/zh_cn::tutorial:mixin_introduction" target="_blank" rel="noreferrer">Mixin 介绍</a> 。</li><li><strong>Gradle</strong>： 用于构建和编译模组的自动化构建工具，Fabric 用其构建模组。</li><li><strong>映射（Mappings）</strong>： 将被混淆的代码转化为人类可读代码的映射的集合。</li><li><strong>混淆（Obfuscation）</strong>： 使代码无法被人类阅读的过程，Mojang 用其来保护 Minecraft 的源代码。</li><li><strong>重映射（Remapping）</strong>： 将混淆代码映射为人类可读代码的过程。</li></ul><h2 id="what-is-fabric" tabindex="-1">Fabric 是什么？ <a class="header-anchor" href="#what-is-fabric" aria-label="Permalink to “Fabric 是什么？”">​</a></h2><p>Fabric 是用于 Minecraft: Java Edition 的轻量级模组开发工具链。</p><p>Fabric 旨在成为简单易用的模组开发平台。 Fabric 是由社区驱动的项目，而且开源，这意味着任何人都可以为项目做出贡献。</p><p>你应该了解的 Fabric 的四个主要组成部分：</p><ul><li><strong>Fabric Loader</strong>： 灵活的独立于平台的模组加载器，专为 Minecraft 及其他游戏和应用程序而设计。</li><li><strong>Fabric Loom</strong>：Gradle 插件，使开发者能够轻松开发和调试模组。</li><li><strong>Fabric API</strong>：一套 API 和工具，供模组开发者在创建模组时使用。</li><li><strong>Yarn</strong>： 一套开放的 Minecraft 映射表，在 Creative Commons Zero 许可证下供所有人任意使用。</li></ul><h2 id="why-is-fabric-necessary-to-mod-minecraft" tabindex="-1">为什么开发 Minecraft 模组需要 Fabric？ <a class="header-anchor" href="#why-is-fabric-necessary-to-mod-minecraft" aria-label="Permalink to “为什么开发 Minecraft 模组需要 Fabric？”">​</a></h2><blockquote><p>“模组（Modding）”是指修改游戏以改变其行为或添加新功能的过程，就 Minecraft 而言，这可以是添加新物品、方块或实体，也可以是改变游戏机制或添加新的游戏模式。</p></blockquote><p>Minecraft: Java Edition 被 Mojang 混淆，因此很难单独修改。 不过，在 Fabric 等模组开发工具的帮助下，修改变得更加容易。 有一些映射系统可以协助这一过程。</p><p>Loom 使用这些映射将混淆代码重映射为人类可读的格式，使模组开发者更容易理解和修改游戏代码。 在这方面，Yarn 是一个富有人气且十分优秀的映射选择，但也有其他选择。 每个映射表项目都有自己的优势和侧重点。</p><p>Loom 可让你轻松开发且编译重映射模组的代码，而 Fabric Loader 可让你将这些模组加载到游戏中。</p><h2 id="what-does-fabric-api-provide-and-why-is-it-needed" tabindex="-1">Fabric API 提供哪些功能，为什么需要它？ <a class="header-anchor" href="#what-does-fabric-api-provide-and-why-is-it-needed" aria-label="Permalink to “Fabric API 提供哪些功能，为什么需要它？”">​</a></h2><blockquote><p>Fabric API 是一套 API 和工具，供模组开发者在创建模组时使用。</p></blockquote><p>Fabric API 在 Minecraft 现有功能的基础上提供了一系列使开发更方便的 API。例如，提供新的 Hook 和事件供开发者使用，或提供新的实用程序和工具让魔改变得更容易，如访问加宽器（Access Wideners）和访问内部注册表（如可堆肥物品注册表）的能力。</p><p>虽然 Fabric API 提供了强大的功能，但有些任务，如基本的方块注册，不使用 Fabric API 也能完成。</p>`,22)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};